    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        //     {
        //         "base": "usdt",
        //         "quote": "twd",
        //         "side": "ask",
        //         "price": "32.039",
        //         "volume": "1",
        //         "fee": "6407800",
        //         "feeCurrency": "twd",
        //         "transactionTimestamp": 1694667358,
        //         "eventTimestamp": 1694667358,
        //         "orderID": 390733918,
        //         "orderType": "LIMIT",
        //         "matchID": "bd07673a-94b1-419e-b5ee-d7b723261a5d",
        //         "isMarket": false,
        //         "isMaker": false
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(trade, "matchID");
        Object orderId = this.safeString(trade, "orderID");
        Object timestamp = this.safeTimestamp(trade, "transactionTimestamp");
        Object baseId = this.safeString(trade, "base");
        Object quoteId = this.safeString(trade, "quote");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object symbol = this.symbol(Helpers.add(Helpers.add(base, "/"), quote));
        market = this.safeMarket(symbol, market);
        Object price = this.safeString(trade, "price");
        Object type = this.safeStringLower(trade, "orderType");
        Object side = this.safeString(trade, "side");
        if (Helpers.isTrue(!Helpers.isEqual(side, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(side, "ask")))
            {
                side = "sell";
            } else if (Helpers.isTrue(Helpers.isEqual(side, "bid")))
            {
                side = "buy";
            }
        }
        Object amount = this.safeString(trade, "volume");
        Object fee = null;
        Object feeAmount = this.safeString(trade, "fee");
        Object feeSymbol = this.safeCurrencyCode(this.safeString(trade, "feeCurrency"));
        if (Helpers.isTrue(!Helpers.isEqual(feeAmount, null)))
        {
            final Object finalFeeAmount = feeAmount;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeAmount );
                put( "currency", feeSymbol );
                put( "rate", null );
            }};
        }
        Object isMaker = this.safeValue(trade, "isMaker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(isMaker, null)))
        {
            if (Helpers.isTrue(isMaker))
            {
                takerOrMaker = "maker";
            } else
            {
                takerOrMaker = "taker";
            }
        }
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "order", orderId );
            put( "timestamp", timestamp );
            put( "datetime", BitoproCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "type", type );
            put( "side", finalSide );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

